import json
with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

def extract(data):
    pkgs = {}
    for proj in data.get('projects', []):
        name = proj['path'].split('/')[-1]
        for fw in proj.get('frameworks', []):
            for pkg in fw.get('topLevelPackages', []):
                pkgs[(name, pkg['id'])] = pkg['resolvedVersion']
    return pkgs

b = extract(baseline)
a = extract(after)
changes = []
for k in sorted(set(b) | set(a)):
    bv = b.get(k, 'N/A')
    av = a.get(k, 'N/A')
    status = 'Unchanged' if bv == av else f'Changed: {bv} -> {av}'
    if bv != av: changes.append((k[0], k[1], bv, av))

if changes:
    print('CHANGES DETECTED:')
    for c in changes: print(f'  {c[0]} | {c[1]} | {c[2]} -> {c[3]}')
else:
    print('NO CHANGES - conversion is fully version-neutral')

print()
print('All packages:')
for k in sorted(set(b) | set(a)):
    bv = b.get(k, 'N/A')
    av = a.get(k, 'N/A')
    print(f'  {k[0]:12s} | {k[1]:52s} | {bv:8s} | {av:8s}')
"

